alias netstat {
    local('$bid $args $choice $mask $has_v4 $has_v6 $has_tcp $has_udp');
    $bid = $1;

    $mask = 0;

    if (size(@_) <= 1) {
        $mask = 0x1111;
    } else {
        $args = join(' ', sublist(@_, 1));
        $has_v4 = 1;
        $has_v6 = 1;
        $has_tcp = 1;
        $has_udp = 1;
        if(indexOf($args, "ipv4") is $null){
            $has_v4 = 0;
        }
        if(indexOf($args, "ipv6") is $null){
            $has_v6 = 0;
        }
        if(indexOf($args, "tcp") is $null){
            $has_tcp = 0;
        }
        if(indexOf($args, "udp") is $null){
            $has_udp = 0;
        }
        if (!$has_v4 && !$has_v6) { $has_v4 = 1; $has_v6 = 1; }
        if (!$has_tcp && !$has_udp) { $has_tcp = 1; $has_udp = 1; }

        if ($has_v4 && $has_tcp) { $mask = $mask | 0x0001; }
        if ($has_v6 && $has_tcp) { $mask = $mask | 0x0010; }
        if ($has_v4 && $has_udp) { $mask = $mask | 0x0100; }
        if ($has_v6 && $has_udp) { $mask = $mask | 0x1000; }
    }
    beacon_inline_execute ($1, readbof($1, "netstat", $null, "T1049"), "go", pack("i", $mask));

