        berror($1, beacon_command_detail("schtasksquery"));
        return;
    } else if(size(@_) == 2)
    {
        $taskname = $2;
    } else if(size(@_) == 3)
    {
        $server = $2;
        $taskname = $3;
    } else 
    {
        berror($1, "Invalid Usage");
        berror($1, beacon_command_detail("schtasksquery"));
        return;
    }
    bschtasksquery($1, $server, $taskname);

